    private boolean isHostAllowed(String host) {
        return allowedHosts.stream().anyMatch(allowed -> {
            if (allowed.endsWith(".*")) {
                return host.startsWith(allowed.substring(0, allowed.length() - 1));
            }
            return host.equals(allowed);
        });
    }

    private boolean isPrivateAddress(InetAddress address) {
        return address.isLoopbackAddress() ||
                address.isAnyLocalAddress() ||
                address.isLinkLocalAddress() ||
                address.isSiteLocalAddress() ||
                isRFC1918Address(address);
    }

    private boolean isRFC1918Address(InetAddress address) {
        byte[] addr = address.getAddress();
        if (addr.length == 4) {
            int firstByte = addr[0] & 0xFF;
            int secondByte = addr[1] & 0xFF;
            return (firstByte == 10) ||
                    (firstByte == 172 && (secondByte >= 16 && secondByte <= 31)) ||
                    (firstByte == 192 && secondByte == 168);
        }
        return false;
    }

